Stage 3: enforceQuota

Monthly token quota enforcement — prevents users from exceeding their tier's monthly allocation:

export const enforceQuota: PipelineStage = async (req, ctx) => {
const monthlyQuota = {
free: 10_000,
starter: 50_000,
professional: 500_000,
business: 2_000_000,
};
const quota = monthlyQuota[ctx.user.subscriptionLevel] ?? monthlyQuota.free;
const usage = await getMonthlyUsage(ctx.user.id);
if (usage >= quota) {
return NextResponse.json(
{
error: 'Monthly quota exceeded',
usage,
quota,
resetDate: getQuotaResetDate(),
},
{ status: 402 } // Payment Required
);
}
ctx.quotaRemaining = quota - usage;
return null;
};

